import Image from "next/image";
import Link from "next/link";
import { ProjectCard } from "@/components/ProjectCard";
import { projects } from "@/lib/projects";

export default function HomePage() {
  return (
    <main>
      {/* ── Hero ── */}
      <div className="site-shell">
        <section className="hero-section">
          {/* Left */}
          <div className="hero-left">
            <h1 className="hi-line">Hi! I&apos;m <span>Мухамед</span></h1>
            <div className="role-row">
              <span className="role-line"></span>
              Full-Stack &amp; Java Developer
            </div>
            <p className="hero-desc">
              Building scalable systems, clean APIs, and real-world applications
              that companies can depend on.
            </p>
            <div className="hero-actions">
              <Link href="/contact" className="btn btn-primary">Let&apos;s Talk ↗</Link>
              <a href="/cv.pdf" className="btn btn-outline" download>Download CV ↓</a>
            </div>
            <div className="social-strip">
              <span className="social-divider"></span>
              <a href="https://github.com/alwazirmbusiness-dev" target="_blank" rel="noreferrer">GitHub</a>
              <a href="https://linkedin.com/in/alwazirtech-dev" target="_blank" rel="noreferrer">LinkedIn</a>
              <a href="mailto:alwazirm.business@gmail.com">Email</a>
            </div>
          </div>

          {/* Center photo */}
          <div className="hero-photo-col">
            <div className="hero-photo-wrap">
              <div className="hero-photo-glow"></div>
              <Image
                src="/images/portfoliopic.png"
                alt="Alwaz — Full-Stack Developer"
                width={380}
                height={500}
                priority
                style={{ objectFit: "contain", objectPosition: "bottom", width: "100%", height: "auto" }}
              />
            </div>
          </div>

          {/* Right stats */}
          <div className="hero-right">
            <div className="stat-item">
              <p className="stat-num">1+</p>
              <p className="stat-label">Years of experience</p>
            </div>
            <div className="stat-item">
              <p className="stat-num">10+</p>
              <p className="stat-label">Projects delivered</p>
            </div>
            <div className="stat-item">
              <p className="stat-num">5+</p>
              <p className="stat-label">Technologies mastered</p>
            </div>
            <div className="tech-strip">
              {["Java", "Next.js", "XML", "Docker"].map((t) => (
                <span key={t} className="tech-chip">{t}</span>
              ))}
            </div>
          </div>
        </section>
      </div>

      {/* ── Services ── */}
      <section className="section" id="services">
        <div className="site-shell">
          <div className="services-header">
            <div>
              <p className="section-kicker">Core Expertise</p>
              <h2 className="section-title">WHAT I&apos;M<br />STRONG AT</h2>
            </div>
            <div className="services-right">
              <p className="services-desc">
                These are not random services. This section shows what companies
                can hire me for immediately based on real shipped work.
              </p>
              <Link href="/projects" className="btn-all-service">All Projects →</Link>
            </div>
          </div>

          <div className="services-grid">
            <div className="service-card">
              <div className="service-icon">🎵</div>
              <h3>Android Music Apps (Java + XML)</h3>
              <p>Published mobile app experience with Java/XML architecture, UI flows, and release-ready delivery for Google Play.</p>
              <span className="read-more">Play Store Work →</span>
            </div>
            <div className="service-card">
              <div className="service-icon">🖥️</div>
              <h3>Next.js Full-Stack Web</h3>
              <p>End-to-end systems using Next.js, JavaScript, HTML, CSS, APIs, and clean code structures for maintainable products.</p>
              <span className="read-more">See Web Projects →</span>
            </div>
            <div className="service-card">
              <div className="service-icon">🐳</div>
              <h3>Backend, Docker &amp; Architecture</h3>
              <p>Java backend APIs, debugging, performance fixes, and Dockerized deployments with strong project structure and delivery discipline.</p>
              <span className="read-more">Architecture Proof →</span>
            </div>
          </div>
        </div>
      </section>

      {/* ── Portfolio ── */}
      <section className="section" id="portfolio">
        <div className="site-shell">
          <div className="portfolio-header">
            <p className="section-kicker" style={{ justifyContent: "center" }}>Let&apos;s have a look at my</p>
            <h2 className="section-title">
              <span className="sparkle">✦</span> portfolio <span className="sparkle">✦</span>
            </h2>
            <p className="portfolio-desc">
              Company case studies, personal projects with full GitHub code, and live demos.
            </p>
          </div>

          <div className="filter-tabs">
            {["All", "Mobile App", "Full-Stack", "Java Backend", "Docker"].map((tab) => (
              <button key={tab} className={`filter-tab${tab === "All" ? " active" : ""}`}>{tab}</button>
            ))}
          </div>

          <div className="project-grid">
            {projects.map((project) => (
              <ProjectCard key={project.slug} project={project} />
            ))}
          </div>
        </div>
      </section>
    </main>
  );
}
